from lxml import etree

def process_soap_request(xml_data):
    try:
        # Load the XML data
        root = etree.fromstring(xml_data, etree.DTD(etree.XML(xml_data)))
        
        # Extract the SOAP envelope
        envelope = root.find('{http://schemas.xmlsoap.org/soap/envelope/}Envelope')
        
        if envelope is not None:
            # Extract the message body
            body = envelope.find('{http://schemas.xmlsoap.org/soap/envelope/}Body')
            if body is not None:
                return etree.tostring(body, pretty_print=True).decode('utf-8')
            else:
                raise ValueError("SOAP Body not found")
        else:
            raise ValueError("SOAP Envelope not found")
    
    except etree.XMLSyntaxError as e:
        print(f"XML Syntax Error: {e}")
        return None
    except etree.DocumentInvalid as e:
        print(f"DTD Validation Error: {e}")
        return None

